import{_ as a,o as t,c as d,a2 as r}from"./chunks/framework.Cd7uensT.js";const p=JSON.parse('{"title":"设备字段必填规则与可见性同步设计","description":"","frontmatter":{},"headers":[],"relativePath":"dev/specs/device-field-required.md","filePath":"dev/specs/device-field-required.md","lastUpdated":1781600343000}'),i={name:"dev/specs/device-field-required.md"};function o(l,e,c,h,s,n){return t(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="设备字段必填规则与可见性同步设计" tabindex="-1">设备字段必填规则与可见性同步设计 <a class="header-anchor" href="#设备字段必填规则与可见性同步设计" aria-label="Permalink to &quot;设备字段必填规则与可见性同步设计&quot;">​</a></h1><blockquote><p>版本：1.0.0 | 更新日期：2026-06-12</p></blockquote><h2 id="问题概述" tabindex="-1">问题概述 <a class="header-anchor" href="#问题概述" aria-label="Permalink to &quot;问题概述&quot;">​</a></h2><p>设备字段管理页面允许用户配置每个字段的是否必填（<code>required</code>）和是否可见（<code>visible</code>），但在设备管理页面添加/编辑设备时，这些配置完全不生效。</p><h3 id="现状问题" tabindex="-1">现状问题 <a class="header-anchor" href="#现状问题" aria-label="Permalink to &quot;现状问题&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层面</th><th>当前行为</th><th>预期行为</th></tr></thead><tbody><tr><td><strong>后端 Joi Schema</strong></td><td>硬编码写死，不查询数据库</td><td>从 DeviceField 表动态读取 required 配置</td></tr><tr><td><strong>前端表单渲染</strong></td><td>rackId/position/height 跳过字段配置，硬编码必填</td><td>跟随字段配置，但对强依赖字段做防护</td></tr></tbody></table><h2 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h2><h3 id="后端改动" tabindex="-1">后端改动 <a class="header-anchor" href="#后端改动" aria-label="Permalink to &quot;后端改动&quot;">​</a></h3><p>动态 Joi Schema 生成：根据 <code>DeviceField</code> 表的配置动态构建 Joi 验证 schema。</p><h3 id="前端改动" tabindex="-1">前端改动 <a class="header-anchor" href="#前端改动" aria-label="Permalink to &quot;前端改动&quot;">​</a></h3><ul><li>表单渲染改为从后端字段配置动态生成</li><li>特殊字段（如 rackId）的联动逻辑保留但跟随可见性配置</li><li>创建/编辑模式统一使用动态渲染</li></ul><p>更多详情请查看完整设计文档。</p>',12)])])}const _=a(i,[["render",o]]);export{p as __pageData,_ as default};
